    (json.from ||
     json.From ||
     json.sender ||
     "").toLowerCase();

  // Exclude common no-reply patterns
  const blockedPatterns = [
    "no-reply",
    "noreply",
    "do-not-reply",
    "donotreply"
  ];

  return !blockedPatterns.some(pattern =>
    from.includes(pattern)
  );
});

return filtered;

