  const aiDraft = aiItems[index].json?.output?.[0]?.content?.[0]?.text;

  const email = {
    from: data.From,
    fromName: data.From,
    subject: data.Subject,
    body: data.snippet,
    date: data.internalDate,
    messageId: data.id,
    threadId: data.threadId,
    aiDraft: aiDraft,
  };

  return {
    json: email,
  };
});

// Aggregates all email items into a single inbox-style HTML page.

const items = $input.all();

// Normalize incoming emails safely
const emails = items.map(item => {
  const json = item.json || {};

  return {
    from: json.from || "",
    fromName: json.fromName || json.from || "Unknown Sender",
    subject: json.subject || "(No Subject)",
    body: json.body || "",
    date: json.date || Date.now(),
    messageId: json.messageId || Math.random().toString(36).slice(2),
    threadId: json.threadId || "",
    aiDraft: json.aiDraft || "",
  };
});

// ⚙️ CONFIGURE: Set your n8n instance base URL here.
const N8N_BASE_URL = "http://localhost:5678";

// Use "webhook-test" while testing, "webhook" in production.
const webhookPrefix = "webhook-test";

const SUBMIT_URL =
  `${N8N_BASE_URL}/${webhookPrefix}/email-reply-submit`;

const safeEmails = JSON.stringify(emails)
  .replace(/<\/script>/gi, "<\\/script>");

let html = `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>AI Email Reply Assistant</title>

  <script src="https://cdn.tailwindcss.com"></script>
  <script defer src="https://unpkg.com/alpinejs@3.x.x/dist/cdn.min.js"></script>

  <link href="https://fonts.googleapis.com/css2?family=Plus+Jakarta+Sans:wght@300;400;500;600;700&display=swap" rel="stylesheet">

  <style>
    body {
      font-family: 'Plus Jakarta Sans', sans-serif;
      background: #070b14;
    }

    [x-cloak] {
      display: none !important;
    }

    .glass-card {
      background: rgba(255,255,255,0.04);
      backdrop-filter: blur(20px);
      border: 1px solid rgba(255,255,255,0.08);
    }

    .email-item {
      transition: all 0.2s ease;
      cursor: pointer;
      border-left: 3px solid transparent;
    }

    .email-item:hover {
      background: rgba(255,255,255,0.05);
    }

    .email-item.active {
      background: rgba(99,102,241,0.12);
      border-left-color: #6366f1;
    }

    .reply-textarea {
      background: rgba(255,255,255,0.06);
      border: 1px solid rgba(255,255,255,0.12);
      color: white;
      resize: vertical;
    }

    .reply-textarea:focus {
      outline: none;
      border-color: #6366f1;
    }

    .send-btn {
      background: linear-gradient(135deg, #6366f1 0%, #8b5cf6 100%);
    }

    .send-btn:hover {
      opacity: 0.95;
    }

    .email-body-text {
      white-space: pre-wrap;
      word-wrap: break-word;
    }

    /* Slide-out animation for removed emails */
    .email-remove {
      animation: slideOut 0.25s ease forwards;
    }

    @keyframes slideOut {
      to {
        opacity: 0;
        transform: translateX(-100%);
        max-height: 0;
        padding: 0;
        margin: 0;
        overflow: hidden;
      }
    }
  </style>
</head>

<body class="min-h-screen text-white">

<div
  x-data="emailApp()"
  x-cloak
  class="min-h-screen flex flex-col"
>

  <!-- Header -->
  <div class="border-b border-white/10 px-6 py-4 flex justify-between items-center">
    <div>
      <h1 class="text-xl font-bold">
        AI Email Reply Assistant
      </h1>

      <p class="text-slate-400 text-sm">
        Review and approve AI-generated replies
      </p>
    </div>

    <div class="flex gap-3">
      <div class="px-3 py-1 rounded-full bg-yellow-500/20 text-yellow-300 text-sm">
        <span x-text="emails.length"></span> Pending
      </div>

      <div class="px-3 py-1 rounded-full bg-green-500/20 text-green-300 text-sm">
        <span x-text="sentCount"></span> Sent
      </div>
    </div>
  </div>

  <div class="flex flex-1 overflow-hidden">

    <!-- Sidebar -->
    <div class="w-80 border-r border-white/10 overflow-y-auto">

      <!-- Empty state -->
      <div
        x-show="emails.length === 0"
        class="p-8 text-center text-slate-500 text-sm"
      >
        <p class="text-2xl mb-2">🎉</p>
        <p>All emails handled!</p>
      </div>

      <template x-for="(email, idx) in emails" :key="email.messageId">

        <div
          @click="selectEmail(idx)"
          class="email-item p-4 border-b border-white/5"
          :class="{ active: selectedIdx === idx }"
          :id="'email-' + email.messageId"
        >

          <div class="flex justify-between items-start mb-1">
            <p
              class="font-semibold text-sm truncate"
              x-text="email.fromName"
            ></p>
          </div>

          <p
            class="text-slate-300 text-xs truncate mb-1"
            x-text="email.subject"
          ></p>

          <p
            class="text-slate-500 text-xs truncate"
            x-text="(email.body || '').substring(0, 70)"
          ></p>

        </div>

      </template>
    </div>

    <!-- Content -->
    <div class="flex-1 overflow-y-auto p-6">

      <div
        x-show="selectedIdx === null"
        class="h-full flex items-center justify-center text-slate-500"
      >
        <div x-show="emails.length > 0">Select an email</div>
        <div x-show="emails.length === 0">No more emails to review</div>
      </div>

      <div
        x-show="selectedEmail"
        class="grid grid-cols-1 lg:grid-cols-2 gap-6"
      >

        <!-- Original -->
        <div class="glass-card rounded-2xl p-6">

          <h2 class="font-semibold text-lg mb-4">
            Original Email
          </h2>

          <div class="space-y-2 text-sm mb-6">
            <p>
              <span class="text-slate-400">From:</span>
              <span x-text="selectedEmail?.fromName"></span>
            </p>

            <p>
              <span class="text-slate-400">Subject:</span>
              <span x-text="selectedEmail?.subject"></span>
            </p>
          </div>

          <div
            class="email-body-text text-slate-300 text-sm"
            x-text="selectedEmail?.body"
          ></div>
        </div>

        <!-- Reply -->
        <div class="glass-card rounded-2xl p-6 flex flex-col">

          <h2 class="font-semibold text-lg mb-4">
            AI Draft Reply
          </h2>

          <textarea
            x-model="replyText"
            rows="12"
            class="reply-textarea w-full rounded-xl p-4 text-sm flex-1"
          ></textarea>

          <button
            @click="sendReply"
            :disabled="sending"
            class="send-btn mt-4 py-3 rounded-xl font-semibold"
          >
            <span x-show="!sending">
              Approve & Send
            </span>

            <span x-show="sending">
              Sending...
            </span>
          </button>

          <div
            x-show="error"
            class="mt-3 text-red-400 text-sm"
            x-text="error"
          ></div>

        </div>

      </div>
    </div>
  </div>
</div>

<script>
function emailApp() {

  const EMAILS = %%EMAILS_DATA%%;
  const SUBMIT_URL = %%SUBMIT_URL%%;

  return {

    emails: EMAILS.map(e => ({ ...e })),

    selectedIdx: null,
    replyText: '',
    sending: false,
    error: null,
    sentCount: 0,

    get selectedEmail() {
      return this.selectedIdx !== null
        ? this.emails[this.selectedIdx]
        : null;
    },

    selectEmail(idx) {
      this.selectedIdx = idx;
      this.replyText = this.emails[idx].aiDraft || '';
      this.error = null;
    },

    async sendReply() {

      const email = this.emails[this.selectedIdx];
      const currentIdx = this.selectedIdx;

      this.sending = true;
      this.error = null;

      try {

        const res = await fetch(SUBMIT_URL, {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json'
          },
          body: JSON.stringify({
            approvedReply: this.replyText,
            originalFrom: email.from,
            originalSubject: email.subject,
            messageId: email.messageId,
            threadId: email.threadId
          })
        });

        if (!res.ok) {
          throw new Error('Failed');
        }

        // ── Animate out then remove from array ──
        const el = document.getElementById('email-' + email.messageId);
        if (el) {
          el.classList.add('email-remove');
          // Wait for animation to finish before splicing
          await new Promise(resolve => setTimeout(resolve, 260));
        }

        this.sentCount++;
        this.emails.splice(currentIdx, 1);

        // Auto-select next email, or previous if we were at the end
        if (this.emails.length === 0) {
          this.selectedIdx = null;
          this.replyText = '';
        } else {
          const nextIdx = currentIdx < this.emails.length
            ? currentIdx
            : currentIdx - 1;
          this.selectEmail(nextIdx);
        }

      } catch (e) {

        this.error = 'Failed to send reply';

      } finally {

        this.sending = false;
      }
    }
  };
}
</script>

</body>
</html>`;

html = html.replace(
  "%%EMAILS_DATA%%",
  safeEmails
);

html = html.replace(
  "%%SUBMIT_URL%%",
  JSON.stringify(SUBMIT_URL)
);

return [
  {
    json: {
      html
    }
  }
];
